import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [showForgotPassword, setShowForgotPassword] = useState(false);
    const [forgotEmail, setForgotEmail] = useState('');
    const [forgotLoading, setForgotLoading] = useState(false);
    const [resetMessage, setResetMessage] = useState('');
    const [resetError, setResetError] = useState('');
    const [errorMessage, setErrorMessage] = useState('');
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setErrorMessage('');
        try {
            const { data } = await API.post('/auth/login', { email, password });

            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);
            localStorage.setItem('userName', data.userName || data.email || 'User');
            localStorage.setItem('userId', data.userId);
            setErrorMessage('');
            navigate('/dashboard');
        } catch (err) {
            const message = err.response?.data?.message || "Invalid email or password";
            setErrorMessage(message);
            console.error('Login error:', message);
        } finally {
            setLoading(false);
        }
    };

    const handleForgotPassword = async (e) => {
        e.preventDefault();
        setForgotLoading(true);
        setResetError('');
        setResetMessage('');
        try {
            const { data } = await API.post('/auth/forgot-password', { email: forgotEmail });
            setResetMessage(data.message || 'Check your email for password reset instructions');
            // In development, show the reset token
            if (data.resetToken) {
                setResetMessage(`${data.message}\n\nDevelopment - Reset Token: ${data.resetToken}\n\nReset Link: ${data.resetLink}`);
            }
            setForgotEmail('');
        } catch (err) {
            const message = err.response?.data?.message || "An error occurred. Please try again.";
            setResetError(message);
            console.error('Forgot password error:', message);
        } finally {
            setForgotLoading(false);
        }
    };

    return (
        <div style={styles.loginPage}>
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap');
                @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700&display=swap');

                * {
                    margin: 0;
                    padding: 0;
                    box-sizing: border-box;
                    font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
                }

                /* Cyber Grid Background */
                .cyber-grid {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    height: 100%;
                    background: 
                        linear-gradient(90deg, rgba(10, 15, 30, 0.3) 1px, transparent 1px) 0 0 / 50px 50px,
                        linear-gradient(rgba(10, 15, 30, 0.3) 1px, transparent 1px) 0 0 / 50px 50px;
                    z-index: 1;
                    animation: gridMove 40s linear infinite;
                }

                @keyframes gridMove {
                    0% { transform: translate(0, 0); }
                    100% { transform: translate(50px, 50px); }
                }

                /* Floating Orbs with Glow */
                .orb-container {
                    position: absolute;
                    width: 100%;
                    height: 100%;
                    overflow: hidden;
                    z-index: 2;
                }

                .glow-orb {
                    position: absolute;
                    border-radius: 50%;
                    filter: blur(60px);
                    opacity: 0.4;
                }

                .orb-1 {
                    width: 600px;
                    height: 600px;
                    background: radial-gradient(circle at center, #00d4ff 0%, #0072ff 70%, transparent 100%);
                    top: -300px;
                    right: -300px;
                    animation: floatOrb 25s ease-in-out infinite;
                }

                .orb-2 {
                    width: 500px;
                    height: 500px;
                    background: radial-gradient(circle at center, #ff0080 0%, #9d00ff 70%, transparent 100%);
                    bottom: -250px;
                    left: -250px;
                    animation: floatOrb 30s ease-in-out infinite reverse;
                }

                .orb-3 {
                    width: 400px;
                    height: 400px;
                    background: radial-gradient(circle at center, #00ff88 0%, #00b8ff 70%, transparent 100%);
                    top: 50%;
                    left: 10%;
                    animation: floatOrb 35s ease-in-out infinite;
                }

                @keyframes floatOrb {
                    0%, 100% {
                        transform: translate(0, 0) scale(1);
                    }
                    33% {
                        transform: translate(100px, -100px) scale(1.1);
                    }
                    66% {
                        transform: translate(-100px, 100px) scale(0.9);
                    }
                }

                /* Login Card */
                .login-card-wrapper {
                    position: relative;
                    z-index: 10;
                    background: rgba(10, 15, 30, 0.7);
                    backdrop-filter: blur(30px);
                    border: 1px solid rgba(0, 210, 255, 0.2);
                    border-radius: 32px;
                    padding: 60px 50px;
                    width: 100%;
                    max-width: 480px;
                    box-shadow: 
                        0 25px 100px rgba(0, 112, 255, 0.15),
                        0 0 200px rgba(0, 210, 255, 0.05),
                        inset 0 0 100px rgba(0, 210, 255, 0.05);
                    animation: cardAppear 0.8s cubic-bezier(0.4, 0, 0.2, 1);
                    overflow: hidden;
                }

                .login-card-wrapper::before {
                    content: '';
                    position: absolute;
                    top: 0;
                    left: 0;
                    right: 0;
                    height: 3px;
                    background: linear-gradient(90deg, #00d4ff, #0072ff, #ff0080, #9d00ff);
                    animation: borderFlow 4s linear infinite;
                }

                @keyframes borderFlow {
                    0% { background-position: 0% 50%; }
                    100% { background-position: 400% 50%; }
                }

                @keyframes cardAppear {
                    0% {
                        opacity: 0;
                        transform: translateY(50px) scale(0.95);
                    }
                    100% {
                        opacity: 1;
                        transform: translateY(0) scale(1);
                    }
                }

                /* Header */
                .login-header {
                    text-align: center;
                    margin-bottom: 50px;
                    position: relative;
                }

                .brand-icon {
                    width: 80px;
                    height: 80px;
                    background: linear-gradient(135deg, #00d4ff, #0072ff);
                    border-radius: 20px;
                    margin: 0 auto 25px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                    font-size: 36px;
                    color: white;
                    box-shadow: 0 15px 40px rgba(0, 112, 255, 0.4);
                    transform: rotate(45deg);
                    animation: iconFloat 6s ease-in-out infinite;
                }

                .brand-icon span {
                    transform: rotate(-45deg);
                    font-weight: 800;
                }

                @keyframes iconFloat {
                    0%, 100% { transform: rotate(45deg) translateY(0); }
                    50% { transform: rotate(45deg) translateY(-10px); }
                }

                .login-title {
                    font-size: 3.5rem;
                    font-weight: 900;
                    background: linear-gradient(135deg, #00d4ff, #0072ff, #9d00ff);
                    -webkit-background-clip: text;
                    -webkit-text-fill-color: transparent;
                    background-clip: text;
                    margin-bottom: 12px;
                    letter-spacing: -2px;
                    font-family: 'Space Grotesk', sans-serif;
                }

                .login-subtitle {
                    color: #94a3b8;
                    font-size: 1rem;
                    font-weight: 500;
                    letter-spacing: 3px;
                    text-transform: uppercase;
                    position: relative;
                    display: inline-block;
                }

                .login-subtitle::after {
                    content: '';
                    position: absolute;
                    bottom: -8px;
                    left: 50%;
                    transform: translateX(-50%);
                    width: 60px;
                    height: 2px;
                    background: linear-gradient(90deg, transparent, #00d4ff, transparent);
                }

                /* Form */
                .form-container {
                    display: flex;
                    flex-direction: column;
                    gap: 28px;
                    margin-bottom: 40px;
                }

                .input-group {
                    position: relative;
                }

                .input-label {
                    display: block;
                    color: #cbd5e1;
                    margin-bottom: 12px;
                    font-size: 0.9rem;
                    font-weight: 600;
                    letter-spacing: 1px;
                    text-transform: uppercase;
                    display: flex;
                    align-items: center;
                    gap: 8px;
                }

                .input-icon {
                    font-size: 1.1rem;
                }

                .input-field {
                    width: 100%;
                    padding: 18px 20px;
                    background: rgba(20, 25, 45, 0.6);
                    border: 2px solid rgba(255, 255, 255, 0.1);
                    border-radius: 16px;
                    color: white;
                    font-size: 1rem;
                    font-weight: 500;
                    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
                }

                .input-field:focus {
                    outline: none;
                    border-color: #00d4ff;
                    background: rgba(20, 25, 45, 0.9);
                    box-shadow: 0 0 0 4px rgba(0, 212, 255, 0.15);
                    transform: translateY(-2px);
                }

                .input-field:hover {
                    border-color: rgba(0, 212, 255, 0.3);
                    transform: translateY(-1px);
                }

                .input-field::placeholder {
                    color: #64748b;
                    opacity: 0.7;
                }

                /* Submit Button */
                .login-btn {
                    padding: 18px 30px;
                    background: linear-gradient(135deg, #0072ff 0%, #00d4ff 100%);
                    border: none;
                    border-radius: 16px;
                    color: white;
                    font-size: 1rem;
                    font-weight: 700;
                    cursor: pointer;
                    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
                    font-family: 'Space Grotesk', sans-serif;
                    text-transform: uppercase;
                    letter-spacing: 1.5px;
                    position: relative;
                    overflow: hidden;
                    margin-top: 10px;
                    box-shadow: 0 15px 50px rgba(0, 112, 255, 0.3);
                }

                .login-btn::before {
                    content: '';
                    position: absolute;
                    top: 0;
                    left: -100%;
                    width: 100%;
                    height: 100%;
                    background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.2), transparent);
                    transition: 0.5s;
                }

                .login-btn:hover:not(:disabled) {
                    transform: translateY(-5px);
                    box-shadow: 0 25px 60px rgba(0, 112, 255, 0.4);
                }

                .login-btn:hover:not(:disabled)::before {
                    left: 100%;
                }

                .login-btn:active:not(:disabled) {
                    transform: translateY(-2px);
                }

                .login-btn:disabled {
                    opacity: 0.6;
                    cursor: not-allowed;
                    transform: none !important;
                }

                /* Footer */
                .security-badge {
                    text-align: center;
                    padding: 20px;
                    background: rgba(0, 212, 255, 0.05);
                    border-radius: 16px;
                    border: 1px solid rgba(0, 212, 255, 0.1);
                    color: #00d4ff;
                    font-size: 0.85rem;
                    font-weight: 600;
                    letter-spacing: 1.5px;
                    text-transform: uppercase;
                    position: relative;
                    overflow: hidden;
                }

                .security-badge::before {
                    content: '🔒';
                    margin-right: 10px;
                    animation: lockPulse 2s ease-in-out infinite;
                }

                @keyframes lockPulse {
                    0%, 100% { opacity: 1; }
                    50% { opacity: 0.5; }
                }

                /* Particles */
                .particles {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    height: 100%;
                    pointer-events: none;
                    z-index: 3;
                }

                .particle {
                    position: absolute;
                    width: 2px;
                    height: 2px;
                    background: #00d4ff;
                    border-radius: 50%;
                    animation: particleFloat 15s infinite linear;
                }

                @keyframes particleFloat {
                    0% {
                        transform: translateY(100vh) translateX(0);
                        opacity: 0;
                    }
                    10% {
                        opacity: 1;
                    }
                    90% {
                        opacity: 1;
                    }
                    100% {
                        transform: translateY(-100px) translateX(100px);
                        opacity: 0;
                    }
                }

                /* Responsive */
                @media (max-width: 640px) {
                    .login-card-wrapper {
                        padding: 40px 30px;
                        margin: 20px;
                        max-width: calc(100% - 40px);
                    }

                    .login-title {
                        font-size: 2.5rem;
                    }

                    .brand-icon {
                        width: 60px;
                        height: 60px;
                        font-size: 28px;
                    }
                }
            `}</style>

            {/* Animated Grid Background */}
            <div className="cyber-grid"></div>

            {/* Glowing Orbs */}
            <div className="orb-container">
                <div className="glow-orb orb-1"></div>
                <div className="glow-orb orb-2"></div>
                <div className="glow-orb orb-3"></div>
            </div>

            {/* Animated Particles */}
            <div className="particles" id="particles"></div>

            {/* Login Card */}
            <div className="login-card-wrapper">
                <div className="login-header">
                    <div className="brand-icon">
                        <span>T</span>
                    </div>
                    <div className="login-title">TMS PRO</div>
                    <div className="login-subtitle">Secure Access Portal</div>
                </div>

                {!showForgotPassword ? (
                    <form onSubmit={handleLogin} className="form-container">
                        {errorMessage && (
                            <div className="error-message" style={{
                                padding: '12px 16px',
                                backgroundColor: 'rgba(239, 68, 68, 0.1)',
                                border: '1px solid rgba(239, 68, 68, 0.3)',
                                borderRadius: '8px',
                                color: '#ff6b6b',
                                fontSize: '0.9rem',
                                marginBottom: '10px'
                            }}>
                                ⚠️ {errorMessage}
                            </div>
                        )}

                        <div className="input-group">
                            <label className="input-label">
                                <span className="input-icon">📧</span>
                                Enterprise Email
                            </label>
                            <input 
                                id="email"
                                type="email" 
                                className="input-field"
                                placeholder="admin@enterprise.com" 
                                value={email}
                                onChange={e => setEmail(e.target.value)} 
                                required 
                            />
                        </div>

                        <div className="input-group">
                            <label className="input-label">
                                <span className="input-icon">🔐</span>
                                Access Key
                            </label>
                            <input 
                                id="password"
                                type="password" 
                                className="input-field"
                                placeholder="••••••••••••" 
                                value={password}
                                onChange={e => setPassword(e.target.value)} 
                                required 
                            />
                        </div>

                        <button type="submit" className="login-btn" disabled={loading}>
                            {loading ? '🛡️ Verifying Credentials...' : '⚡ Launch Dashboard'}
                        </button>

                        <div style={{
                            textAlign: 'center',
                            marginTop: '20px',
                            paddingTop: '20px',
                            borderTop: '1px solid rgba(255, 255, 255, 0.1)'
                        }}>
                            <button 
                                type="button"
                                onClick={() => {
                                    setShowForgotPassword(true);
                                    setErrorMessage('');
                                    setEmail('');
                                    setPassword('');
                                }}
                                style={{
                                    background: 'none',
                                    border: 'none',
                                    color: '#00d4ff',
                                    cursor: 'pointer',
                                    fontSize: '0.9rem',
                                    fontWeight: '600',
                                    textDecoration: 'underline',
                                    transition: 'color 0.3s ease'
                                }}
                                onMouseEnter={(e) => e.target.style.color = '#0072ff'}
                                onMouseLeave={(e) => e.target.style.color = '#00d4ff'}
                            >
                                🔑 Forgot Password?
                            </button>
                        </div>
                    </form>
                ) : (
                    <form onSubmit={handleForgotPassword} className="form-container">
                        {resetError && (
                            <div className="error-message" style={{
                                padding: '12px 16px',
                                backgroundColor: 'rgba(239, 68, 68, 0.1)',
                                border: '1px solid rgba(239, 68, 68, 0.3)',
                                borderRadius: '8px',
                                color: '#ff6b6b',
                                fontSize: '0.9rem',
                                marginBottom: '10px'
                            }}>
                                ⚠️ {resetError}
                            </div>
                        )}

                        {resetMessage && (
                            <div className="success-message" style={{
                                padding: '12px 16px',
                                backgroundColor: 'rgba(34, 197, 94, 0.1)',
                                border: '1px solid rgba(34, 197, 94, 0.3)',
                                borderRadius: '8px',
                                color: '#22c55e',
                                fontSize: '0.9rem',
                                marginBottom: '10px',
                                whiteSpace: 'pre-wrap',
                                wordBreak: 'break-word'
                            }}>
                                ✅ {resetMessage}
                            </div>
                        )}

                        <p style={{
                            color: '#cbd5e1',
                            fontSize: '0.9rem',
                            marginBottom: '20px',
                            textAlign: 'center',
                            lineHeight: '1.5'
                        }}>
                            Enter your email address and we'll send you a link to reset your password.
                        </p>

                        <div className="input-group">
                            <label className="input-label">
                                <span className="input-icon">📧</span>
                                Enterprise Email
                            </label>
                            <input 
                                type="email" 
                                className="input-field"
                                placeholder="admin@enterprise.com" 
                                value={forgotEmail}
                                onChange={e => setForgotEmail(e.target.value)} 
                                required 
                            />
                        </div>

                        <button type="submit" className="login-btn" disabled={forgotLoading}>
                            {forgotLoading ? '📧 Sending...' : '📧 Send Reset Link'}
                        </button>

                        <div style={{
                            textAlign: 'center',
                            marginTop: '20px',
                            paddingTop: '20px',
                            borderTop: '1px solid rgba(255, 255, 255, 0.1)'
                        }}>
                            <button 
                                type="button"
                                onClick={() => {
                                    setShowForgotPassword(false);
                                    setResetMessage('');
                                    setResetError('');
                                    setForgotEmail('');
                                }}
                                style={{
                                    background: 'none',
                                    border: 'none',
                                    color: '#00d4ff',
                                    cursor: 'pointer',
                                    fontSize: '0.9rem',
                                    fontWeight: '600',
                                    textDecoration: 'underline',
                                    transition: 'color 0.3s ease'
                                }}
                                onMouseEnter={(e) => e.target.style.color = '#0072ff'}
                                onMouseLeave={(e) => e.target.style.color = '#00d4ff'}
                            >
                                ← Back to Login
                            </button>
                        </div>
                    </form>
                )}

                <div className="security-badge">
                    Quantum-Encrypted Connection Active
                </div>
            </div>

            {/* Particle Generation Script */}
            <script dangerouslySetInnerHTML={{
                __html: `
                    document.addEventListener('DOMContentLoaded', function() {
                        const particlesContainer = document.getElementById('particles');
                        const particleCount = 50;

                        for (let i = 0; i < particleCount; i++) {
                            const particle = document.createElement('div');
                            particle.className = 'particle';
                            particle.style.left = Math.random() * 100 + 'vw';
                            particle.style.animationDelay = Math.random() * 15 + 's';
                            particle.style.animationDuration = (10 + Math.random() * 10) + 's';
                            particle.style.opacity = 0.3 + Math.random() * 0.7;
                            particle.style.width = particle.style.height = (1 + Math.random() * 2) + 'px';
                            particlesContainer.appendChild(particle);
                        }
                    });
                `
            }} />
        </div>
    );
};

const styles = {
    loginPage: {
        minHeight: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        background: 'linear-gradient(135deg, #000814 0%, #001233 30%, #000814 100%)',
        overflow: 'hidden',
        position: 'relative',
        padding: '20px',
    },
};

export default Login;
